parameters.jsCode:
const content = $input.first().json.message?.content || '';
const brief = $('Parse Briefs').first().json;

return [{
  json: {
    platform: brief.platform,
    day: brief.day,
    type: brief.type,
    language: brief.language,
    content: content,
    hashtags: brief.hashtags,
    status: 'ready',
    generatedAt: new Date().toISOString()
  }
}];
